    {
      "name": "Paper & Pads",
      "url": "https://www.stationerywholesale.co.uk/paper-pads.html"
    },
    {
      "name": "Office Essentials",
      "url": "https://www.stationerywholesale.co.uk/office-essentials.html"
    },
    {
      "name": "Writing Instruments",
      "url": "https://www.stationerywholesale.co.uk/writing-instruments.html"
    }
  ],
  "field_mappings": {
    "product_item": [".product-item", "div.product-item-details"],
    "title": ["a.product-item-link", "h4.product-name a"],
    "price": ["span.price", ".price-wrapper .price", "[data-price-amount]"],
    "url": ["a.product-item-link"],
    "image": [".product-item img.product-image-photo"],
    "ean": ["dt:contains('EAN') + dd", "dt:contains('Barcode') + dd"]
  },
  "pagination": {
    "type": "url_param",
    "param": "p",
    "selector": ".pages a.next"
  },
